-        const disp = if (self.temporary) "del  " else "keep ";
-        const enab = if (self.enabled) "yes" else "no ";
-
-        var buf: [256]u8 = undefined;
-        const info = std.fmt.bufPrint(&buf, "{d:<4} {s} {s}  at {s}:{d}", .{
-            self.number,
-            disp,
-            enab,
-            self.file,
-            self.line,
-        }) catch return result.toOwnedSlice();
-
-        try result.appendSlice(info);
-
-        if (self.cond) |cond| {
-            try result.appendSlice("\n\tstop only if ");
-            try result.appendSlice(cond);
-        }
-
-        if (self.ignore > 0) {
-            var ignore_buf: [64]u8 = undefined;
-            const ignore_str = std.fmt.bufPrint(&ignore_buf, "\n\tignore next {d} hits", .{self.ignore}) catch "";
-            try result.appendSlice(ignore_str);
-        }
-
-        if (self.hits > 0) {
-            var hits_buf: [64]u8 = undefined;
-            const hits_str = std.fmt.bufPrint(&hits_buf, "\n\tbreakpoint already hit {d} time(s)", .{self.hits}) catch "";
-            try result.appendSlice(hits_str);
-        }
-
-        return result.toOwnedSlice();
-    }
-};
-
-// ============================================================================
-// Stop Reasons
-// ============================================================================
-
-/// Reasons for stopping execution
-pub const StopReason = enum {
-    step,
-    next,
-    return_,
-    call,
-    line,
-    breakpoint,
-    exception,
-    quit,
-};
-
-/// Frame information for debugging
-pub const FrameInfo = struct {
-    filename: []const u8,
-    lineno: usize,
-    function: []const u8,
-    code_context: ?[]const u8,
-    locals: ?*anyopaque, // Frame locals (PyDict in CPython)
-};
-
-// ============================================================================
-// Bdb - Base Debugger Class
-// ============================================================================
-
-/// Base debugger class
-pub const Bdb = struct {
-    const Self = @This();
-
-    allocator: std.mem.Allocator,
-
-    // Breakpoint management
-    breakpoints: std.ArrayList(Breakpoint),
-    bp_by_file: hashmap_helper.StringHashMap(std.ArrayList(usize)),
-    next_bp_number: usize,
-
-    // Execution state
-    stop_here: bool,
-    return_frame: ?*FrameInfo,
-    stop_reason: ?StopReason,
-
-    // Step control
-    skip: ?hashmap_helper.StringHashMap(void),
-    stopframe: ?*FrameInfo,
-    returnframe: ?*FrameInfo,
-    quitting: bool,
-
-    // Current frame
-    curframe: ?*FrameInfo,
-    curindex: usize,
-    stack: std.ArrayList(*FrameInfo),
-
-    // Callbacks (can be set by subclasses)
-    on_stop: ?*const fn (*Self) void,
-    on_breakpoint: ?*const fn (*Self, *const Breakpoint) void,
-
-    pub fn init(allocator: std.mem.Allocator) Self {
-        return .{
-            .allocator = allocator,
-            .breakpoints = std.ArrayList(Breakpoint).init(allocator),
-            .bp_by_file = hashmap_helper.StringHashMap(std.ArrayList(usize)).init(allocator),
-            .next_bp_number = 1,
-            .stop_here = false,
-            .return_frame = null,
-            .stop_reason = null,
-            .skip = null,
-            .stopframe = null,
-            .returnframe = null,
-            .quitting = false,
-            .curframe = null,
-            .curindex = 0,
-            .stack = std.ArrayList(*FrameInfo).init(allocator),
-            .on_stop = null,
-            .on_breakpoint = null,
-        };
-    }
-
-    pub fn deinit(self: *Self) void {
-        self.breakpoints.deinit();
-
-        var it = self.bp_by_file.iterator();
-        while (it.next()) |entry| {
-            entry.value_ptr.deinit();
-        }
-        self.bp_by_file.deinit();
-
-        self.stack.deinit();
-    }
-
-    /// Reset the debugger state
-    pub fn reset(self: *Self) void {
-        self.stop_here = false;
-        self.return_frame = null;
-        self.stop_reason = null;
-        self.stopframe = null;
-        self.returnframe = null;
-        self.quitting = false;
-    }
-
-    // ========================================================================
-    // Breakpoint Management
-    // ========================================================================
-
-    /// Set a breakpoint
-    pub fn setBreak(
-        self: *Self,
-        filename: []const u8,
-        lineno: usize,
-        temporary: bool,
-        cond: ?[]const u8,
-        funcname: ?[]const u8,
-    ) !*Breakpoint {
-        const bp = Breakpoint.init(
-            self.next_bp_number,
-            filename,
-            lineno,
-            temporary,
-            cond,
-            funcname,
-        );
-        self.next_bp_number += 1;
-
-        try self.breakpoints.append(bp);
-
-        // Add to file index
-        if (self.bp_by_file.getPtr(filename)) |list| {
-            try list.append(self.breakpoints.items.len - 1);
-        } else {
-            var list = std.ArrayList(usize).init(self.allocator);
-            try list.append(self.breakpoints.items.len - 1);
-            try self.bp_by_file.put(filename, list);
-        }
-
-        return &self.breakpoints.items[self.breakpoints.items.len - 1];
-    }
-
-    /// Clear a breakpoint by number
-    pub fn clearBreak(self: *Self, number: usize) bool {
-        for (self.breakpoints.items, 0..) |*bp, i| {
-            if (bp.number == number) {
-                bp.enabled = false; // Mark as disabled (could also remove)
-                _ = i;
-                return true;
-            }
-        }
-        return false;
-    }
-
-    /// Clear breakpoints at a specific file:line
-    pub fn clearBreakpoint(self: *Self, filename: []const u8, lineno: usize) usize {
-        var cleared: usize = 0;
-        for (self.breakpoints.items) |*bp| {
-            if (std.mem.eql(u8, bp.file, filename) and bp.line == lineno) {
-                bp.enabled = false;
-                cleared += 1;
-            }
-        }
-        return cleared;
-    }
-
-    /// Get breakpoints at a location
-    pub fn getBreaks(self: *Self, filename: []const u8, lineno: usize) std.ArrayList(*Breakpoint) {
-        var result = std.ArrayList(*Breakpoint).init(self.allocator);
-        for (self.breakpoints.items) |*bp| {
-            if (std.mem.eql(u8, bp.file, filename) and bp.line == lineno and bp.enabled) {
-                result.append(bp) catch continue;
-            }
-        }
-        return result;
-    }
-
-    /// Get all breakpoints
-    pub fn getAllBreaks(self: *Self) []Breakpoint {
-        return self.breakpoints.items;
-    }
-
-    /// Check if there's a breakpoint at location
-    pub fn breakHere(self: *Self, filename: []const u8, lineno: usize) bool {
-        for (self.breakpoints.items) |bp| {
-            if (bp.enabled and std.mem.eql(u8, bp.file, filename) and bp.line == lineno) {
-                return true;
-            }
-        }
-        return false;
-    }
-
-    /// Check breakpoint condition and handle hit
-    /// If frame is provided, uses it for condition evaluation context
-    pub fn effectiveBreakpoint(self: *Self, filename: []const u8, lineno: usize) ?*Breakpoint {
-        return self.effectiveBreakpointWithFrame(filename, lineno, null);
-    }
-
-    /// Check breakpoint condition and handle hit with optional frame context
-    pub fn effectiveBreakpointWithFrame(self: *Self, filename: []const u8, lineno: usize, frame: ?*FrameInfo) ?*Breakpoint {
-        for (self.breakpoints.items) |*bp| {
-            if (!bp.enabled) continue;
-            if (!std.mem.eql(u8, bp.file, filename)) continue;
-            if (bp.line != lineno) continue;
-
-            bp.hits += 1;
-
-            // Check ignore count
-            if (bp.ignore > 0) {
-                bp.ignore -= 1;
-                return null;
-            }
-
-            // Check condition
-            if (bp.cond) |cond| {
-                if (!evaluateCondition(cond, frame)) {
-                    // Condition is false, don't break
-                    continue;
-                }
-            }
-
-            return bp;
-        }
-        return null;
-    }
-
-    /// Evaluate a breakpoint condition expression
-    /// Supports simple comparisons: x == value, x != value, x > value, x < value
-    /// Also supports: True, False, and simple variable existence checks
-    fn evaluateCondition(cond: []const u8, frame: ?*FrameInfo) bool {
-        const trimmed = std.mem.trim(u8, cond, " \t\n\r");
-
-        // Handle literal True/False
-        if (std.mem.eql(u8, trimmed, "True") or std.mem.eql(u8, trimmed, "true")) {
-            return true;
-        }
-        if (std.mem.eql(u8, trimmed, "False") or std.mem.eql(u8, trimmed, "false")) {
-            return false;
-        }
-
-        // Handle comparisons
-        if (std.mem.indexOf(u8, trimmed, "==")) |pos| {
-            return evaluateComparison(trimmed[0..pos], trimmed[pos + 2 ..], .eq, frame);
-        }
-        if (std.mem.indexOf(u8, trimmed, "!=")) |pos| {
-            return evaluateComparison(trimmed[0..pos], trimmed[pos + 2 ..], .ne, frame);
-        }
-        if (std.mem.indexOf(u8, trimmed, ">=")) |pos| {
-            return evaluateComparison(trimmed[0..pos], trimmed[pos + 2 ..], .ge, frame);
-        }
-        if (std.mem.indexOf(u8, trimmed, "<=")) |pos| {
-            return evaluateComparison(trimmed[0..pos], trimmed[pos + 2 ..], .le, frame);
-        }
-        if (std.mem.indexOf(u8, trimmed, ">")) |pos| {
-            return evaluateComparison(trimmed[0..pos], trimmed[pos + 1 ..], .gt, frame);
-        }
-        if (std.mem.indexOf(u8, trimmed, "<")) |pos| {
-            return evaluateComparison(trimmed[0..pos], trimmed[pos + 1 ..], .lt, frame);
-        }
-
-        // Check if it's a variable that exists and is truthy
-        if (frame) |f| {
-            if (f.locals.get(trimmed)) |val| {
-                // Non-zero and non-empty values are truthy
-                return !std.mem.eql(u8, val, "0") and !std.mem.eql(u8, val, "") and !std.mem.eql(u8, val, "None");
-            }
-        }
-
-        // Unknown condition - default to true (break)
-        return true;
-    }
-
-    const CompareOp = enum { eq, ne, gt, lt, ge, le };
-
-    fn evaluateComparison(left: []const u8, right: []const u8, op: CompareOp, frame: ?*FrameInfo) bool {
-        const lhs = std.mem.trim(u8, left, " \t");
-        const rhs = std.mem.trim(u8, right, " \t");
-
-        // Get values (from frame locals or as literals)
-        const lhs_val = getConditionValue(lhs, frame);
-        const rhs_val = getConditionValue(rhs, frame);
-
-        // Try numeric comparison first
-        const lhs_num = std.fmt.parseInt(i64, lhs_val, 10) catch null;
-        const rhs_num = std.fmt.parseInt(i64, rhs_val, 10) catch null;
-
-        if (lhs_num != null and rhs_num != null) {
-            const l = lhs_num.?;
-            const r = rhs_num.?;
-            return switch (op) {
-                .eq => l == r,
-                .ne => l != r,
-                .gt => l > r,
-                .lt => l < r,
-                .ge => l >= r,
-                .le => l <= r,
-            };
-        }
-
-        // Fall back to string comparison
-        const cmp = std.mem.order(u8, lhs_val, rhs_val);
-        return switch (op) {
-            .eq => cmp == .eq,
-            .ne => cmp != .eq,
-            .gt => cmp == .gt,
-            .lt => cmp == .lt,
-            .ge => cmp == .gt or cmp == .eq,
-            .le => cmp == .lt or cmp == .eq,
-        };
-    }
-
-    fn getConditionValue(expr: []const u8, frame: ?*FrameInfo) []const u8 {
-        // Try to get from frame locals
-        if (frame) |f| {
-            if (f.locals.get(expr)) |val| {
-                return val;
-            }
-        }
-
-        // Strip quotes for string literals
-        if (expr.len >= 2) {
-            if ((expr[0] == '"' and expr[expr.len - 1] == '"') or
-                (expr[0] == '\'' and expr[expr.len - 1] == '\''))
-            {
-                return expr[1 .. expr.len - 1];
-            }
-        }
-
-        // Return as literal
-        return expr;
-    }
-
-    // ========================================================================
-    // Execution Control
-    // ========================================================================
-
-    /// Continue execution until next breakpoint
-    pub fn setContinue(self: *Self) void {
-        self.stopframe = null;
-        self.returnframe = null;
-        self.quitting = false;
-        self.stop_here = false;
-    }
-
-    /// Step to next line (into functions)
-    pub fn setStep(self: *Self) void {
-        self.stop_here = true;
-        self.stop_reason = .step;
-    }
-
-    /// Step to next line (over functions)
-    pub fn setNext(self: *Self, frame: *FrameInfo) void {
-        self.stop_here = true;
-        self.stopframe = frame;
-        self.stop_reason = .next;
-    }
-
-    /// Continue until return from current function
-    pub fn setReturn(self: *Self, frame: *FrameInfo) void {
-        self.stop_here = true;
-        self.returnframe = frame;
-        self.stop_reason = .return_;
-    }
-
-    /// Stop execution
-    pub fn setQuit(self: *Self) void {
-        self.quitting = true;
-        self.stop_reason = .quit;
-    }
-
-    /// Check if should stop at this frame
-    pub fn stopHere(self: *Self, frame: *FrameInfo) bool {
-        if (self.stop_here) return true;
-        if (self.stopframe) |sf| {
-            return sf == frame;
-        }
-        return false;
-    }
-
-    // ========================================================================
-    // Frame Operations
-    // ========================================================================
-
-    /// Set up stack from current frame
-    pub fn setup(self: *Self, frame: *FrameInfo) void {
-        self.curframe = frame;
-        self.stack.clearRetainingCapacity();
-        self.stack.append(frame) catch {};
-        self.curindex = 0;
-    }
-
-    /// Move up one frame
-    pub fn frameUp(self: *Self) ?*FrameInfo {
-        if (self.curindex + 1 < self.stack.items.len) {
-            self.curindex += 1;
-            self.curframe = self.stack.items[self.curindex];
-            return self.curframe;
-        }
-        return null;
-    }
-
-    /// Move down one frame
-    pub fn frameDown(self: *Self) ?*FrameInfo {
-        if (self.curindex > 0) {
-            self.curindex -= 1;
-            self.curframe = self.stack.items[self.curindex];
-            return self.curframe;
-        }
-        return null;
-    }
-
-    // ========================================================================
-    // Trace Functions (callbacks from execution)
-    // ========================================================================
-
-    /// Called on function call
-    pub fn dispatchCall(self: *Self, frame: *FrameInfo) void {
-        if (self.quitting) return;
-
-        // Check if we should stop
-        if (self.stopframe != null or self.returnframe != null) {
-            // Stepping through, might need to stop
-        }
-
-        self.stack.append(frame) catch {};
-    }
-
-    /// Called on line execution
-    pub fn dispatchLine(self: *Self, frame: *FrameInfo) void {
-        if (self.quitting) return;
-
-        // Check for breakpoint
-        if (self.effectiveBreakpoint(frame.filename, frame.lineno)) |bp| {
-            self.stop_reason = .breakpoint;
-            if (self.on_breakpoint) |cb| {
-                cb(self, bp);
-            }
-            // If temporary, clear it
-            if (bp.temporary) {
-                bp.enabled = false;
-            }
-        }
-
-        // Check if we should stop
-        if (self.stopHere(frame)) {
-            self.curframe = frame;
-            if (self.on_stop) |cb| {
-                cb(self);
-            }
-        }
-    }
-
-    /// Called on function return
-    pub fn dispatchReturn(self: *Self, frame: *FrameInfo, retval: ?*anyopaque) void {
-        _ = retval;
-        if (self.quitting) return;
-
-        if (self.returnframe) |rf| {
-            if (rf == frame) {
-                self.stop_reason = .return_;
-                self.curframe = frame;
-                if (self.on_stop) |cb| {
-                    cb(self);
-                }
-            }
-        }
-
-        _ = self.stack.popOrNull();
-    }
-
-    /// Called on exception
-    pub fn dispatchException(self: *Self, frame: *FrameInfo, exc_info: anytype) void {
-        _ = exc_info;
-        if (self.quitting) return;
-
-        self.stop_reason = .exception;
-        self.curframe = frame;
-        if (self.on_stop) |cb| {
-            cb(self);
-        }
-    }
-
-    // ========================================================================
-    // Source Code Helpers
-    // ========================================================================
-
-    /// Format a stack entry for display
-    pub fn formatStackEntry(self: *Self, frame: *FrameInfo) ![]u8 {
-        _ = self;
-        var buf: [512]u8 = undefined;
-        const str = std.fmt.bufPrint(&buf, "  File \"{s}\", line {d}, in {s}", .{
-            frame.filename,
-            frame.lineno,
-            frame.function,
-        }) catch return "";
-
-        return self.allocator.dupe(u8, str) catch return "";
-    }
-
-    /// Print stack trace
-    pub fn printStack(self: *Self, writer: anytype) !void {
-        try writer.writeAll("Traceback (most recent call last):\n");
-        for (self.stack.items) |frame| {
-            const entry = try self.formatStackEntry(frame);
-            defer self.allocator.free(entry);
-            try writer.print("{s}\n", .{entry});
-        }
-    }
-};
