-pub fn checkfuncname(bp: *const Breakpoint, frame: *const FrameInfo) bool {
-    if (bp.funcname) |funcname| {
-        return std.mem.eql(u8, funcname, frame.function);
-    }
-    return true; // No funcname restriction
-}
