+    allocator: std.mem.Allocator,
+    host: []const u8,
+    port: u16,
+    sock: ?std.posix.socket_t,
+    file: ?std.net.Stream,
+    welcome: ?[]const u8,
+    capabilities: hashmap_helper.StringHashMap(void),
