+        if (std.mem.indexOf(u8, resp_buf[0..total_len], "OK")) |_| {
+            typ = .OK;
+        } else if (std.mem.indexOf(u8, resp_buf[0..total_len], "NO")) |_| {
+            typ = .NO;
+        }
+
+        if (self.debugging > 0) {
+            std.debug.print("< {s}\n", .{resp_buf[0..total_len]});
+        }
