+    pub fn get(self: Self, key: []const u8) ?Value {
+        return self.values.get(key);
+    }
+
+    pub fn getString(self: Self, key: []const u8) ?[]const u8 {
+        if (self.values.get(key)) |val| {
+            return switch (val) {
+                .string => |s| s,
+                else => null,
+            };
+        }
+        return null;
+    }
+
+    pub fn getBool(self: Self, key: []const u8) bool {
+        if (self.values.get(key)) |val| {
+            return switch (val) {
+                .boolean => |b| b,
+                else => false,
+            };
+        }
+        return false;
+    }
