+        self.breakpoints.deinit();
+        for (self.stack.items) |*frame| {
+            frame.deinit();
+        }
+        self.stack.deinit();
+        self.commands.deinit();
+        self.commands_doprompt.deinit();
+        self.commands_silent.deinit();
+        self.aliases.deinit();
+    }
