+        try commands_mod.Commands.do_print(self.curframe, self.stdout, arg);
+    }
+
+    /// Pretty print command (pp)
+    pub fn do_pp(self: *Self, arg: []const u8) !void {
+        try commands_mod.Commands.do_pp(self.curframe, self.stdout, arg);
+    }
