-fn writeXMLEscaped(writer: anytype, s: []const u8) !void {
-    for (s) |c| {
-        switch (c) {
-            '<' => try writer.writeAll("&lt;"),
-            '>' => try writer.writeAll("&gt;"),
-            '&' => try writer.writeAll("&amp;"),
-            '"' => try writer.writeAll("&quot;"),
-            '\'' => try writer.writeAll("&apos;"),
-            else => try writer.writeByte(c),
-        }
-    }
-}
