+    pub fn reset(self: *Self) void {
+        self.pos = 0;
+        self.line = 1;
+        self.col = 0;
+        self.at_bol = true;
+        self.pending_dedents = 0;
+        self.done = false;
+        self.indent_stack.clearRetainingCapacity();
+        self.indent_stack.append(self.allocator, 0) catch {};
+    }
